import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Branded — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Branded — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/branded"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Branded — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/branded"}]]},"headers":[],"relativePath":"user-guide/branded.md","filePath":"user-guide/branded.md","lastUpdated":1784902400000}'),r={name:"user-guide/branded.md"};function i(s,e,d,l,c,m){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="branded-—-user-guide" tabindex="-1">Branded — User Guide <a class="header-anchor" href="#branded-—-user-guide" aria-label="Permalink to &quot;Branded — User Guide&quot;">​</a></h1><p>The <strong>Branded</strong> marketplace module lets a workspace map a <strong>custom domain</strong> and use its brand name / logo in emails and web push notifications.</p><h2 id="who-can-use-it" tabindex="-1">Who can use it <a class="header-anchor" href="#who-can-use-it" aria-label="Permalink to &quot;Who can use it&quot;">​</a></h2><ol><li>Purchase or install <strong>Branded</strong> from Marketplace (<code>module:branded</code>).</li><li>You need permission <strong>View branded</strong> / <strong>Manage branded</strong> (<code>branded.view</code> / <code>branded.manage</code>). Workspace admins get both by default.</li></ol><p>Without the module, the Settings <strong>Domain</strong> tab is hidden and custom hostnames never bind to the workspace — even if someone points DNS or an IP at the server.</p><h2 id="map-a-custom-domain" tabindex="-1">Map a custom domain <a class="header-anchor" href="#map-a-custom-domain" aria-label="Permalink to &quot;Map a custom domain&quot;">​</a></h2><ol><li>Open <strong>Settings → Domain</strong>.</li><li>Enter a hostname such as <code>myai.com.pk</code> or <code>app.domain.co.uk</code> (multi-part ccTLDs are supported).</li><li>Save, then create the DNS records shown on the page: <ul><li><strong>TXT</strong> ownership record on <code>_saleos-verification.&lt;your-host&gt;</code></li><li><strong>A</strong> / <strong>AAAA</strong> to the platform server IP(s), <strong>or</strong> <strong>CNAME</strong> to the platform target</li></ul></li><li>Click <strong>Verify DNS</strong>.</li></ol><p>The hostname becomes active only after verification succeeds <strong>and</strong> Branded remains licensed.</p><p>Platform subdomains (for example <code>acme.localhost</code>) stay managed by Central — they are not configured on this tab.</p><h2 id="brand-in-notifications" tabindex="-1">Brand in notifications <a class="header-anchor" href="#brand-in-notifications" aria-label="Permalink to &quot;Brand in notifications&quot;">​</a></h2><p>While Branded is active:</p><ul><li>Tenant emails use your application / company name, logo, and button color in the mail chrome.</li><li>Web push notifications use your logo / favicon and prefix titles with your application name.</li></ul><p>Visual SPA branding (Settings → Branding) remains available to all workspaces; notification white-label and custom domains require Branded.</p><h2 id="remove-or-cancel" tabindex="-1">Remove or cancel <a class="header-anchor" href="#remove-or-cancel" aria-label="Permalink to &quot;Remove or cancel&quot;">​</a></h2><ul><li><strong>Remove</strong> on the Domain tab deletes the custom hostname mapping.</li><li>Cancelling the Branded subscription clears verification so the custom host stops resolving.</li></ul>',15)])])}const h=a(r,[["render",i]]);export{p as __pageData,h as default};
